package com.qinet.feastique.service.consumablesimport com.qinet.feastique.common.mapper.toResponseimport com.qinet.feastique.exception.DuplicateFoundExceptionimport com.qinet.feastique.exception.PermissionDeniedExceptionimport com.qinet.feastique.exception.RequestedEntityNotFoundExceptionimport com.qinet.feastique.exception.UserNotFoundExceptionimport com.qinet.feastique.model.dto.consumables.FoodDtoimport com.qinet.feastique.model.entity.Menuimport com.qinet.feastique.model.entity.consumables.addOn.AddOnimport com.qinet.feastique.model.entity.consumables.addOn.FoodAddOnimport com.qinet.feastique.model.entity.consumables.complement.Complementimport com.qinet.feastique.model.entity.consumables.complement.FoodComplementimport com.qinet.feastique.model.entity.consumables.food.Foodimport com.qinet.feastique.model.entity.discount.Discountimport com.qinet.feastique.model.entity.discount.FoodDiscountimport com.qinet.feastique.model.entity.image.FoodImageimport com.qinet.feastique.model.entity.size.FoodSizeimport com.qinet.feastique.model.entity.user.Vendorimport com.qinet.feastique.model.enums.Availabilityimport com.qinet.feastique.model.enums.Dayimport com.qinet.feastique.model.enums.OrderTypeimport com.qinet.feastique.model.enums.Sizeimport com.qinet.feastique.repository.MenuRepositoryimport com.qinet.feastique.repository.consumables.addOn.AddOnRepositoryimport com.qinet.feastique.repository.consumables.complement.ComplementRepositoryimport com.qinet.feastique.repository.consumables.food.FoodRepositoryimport com.qinet.feastique.repository.discount.DiscountRepositoryimport com.qinet.feastique.repository.user.VendorRepositoryimport com.qinet.feastique.response.consumables.food.FoodResponseimport com.qinet.feastique.security.UserSecurityimport com.qinet.feastique.utility.DuplicateUtilityimport org.springframework.data.domain.Pageimport org.springframework.data.domain.PageRequestimport org.springframework.data.domain.Sortimport org.springframework.stereotype.Serviceimport org.springframework.transaction.annotation.Transactionalimport java.util.*import kotlin.jvm.optionals.getOrElse@Serviceclass FoodService(    private val foodRepository: FoodRepository,    private val vendorRepository: VendorRepository,    private val menuRepository: MenuRepository,    private val duplicateUtility: DuplicateUtility,    private val discountRepository: DiscountRepository,    private val complementRepository: ComplementRepository,    private val addOnRepository: AddOnRepository) {    @Transactional(readOnly = true)    fun getFoodById(id: UUID, vendorDetails: UserSecurity): Food {        val food = foodRepository.findById(id)            .orElseThrow { RequestedEntityNotFoundException("No food found for id: $id") }            .also {                if (it.vendor.id != vendorDetails.id) {                    throw PermissionDeniedException("You do not have permission to access discount.")                }            }        return food    }    @Transactional(readOnly = true)    fun getAllFoods(vendorDetails: UserSecurity, page: Int, size: Int): Page<FoodResponse> {        val pageable = PageRequest.of(page, size, Sort.by("name").ascending())        val foodResponses = foodRepository.findAllByVendorId(vendorDetails.id, pageable).map { it.toResponse() }        return foodResponses    }    @Transactional    fun deleteFood(id: UUID, vendorDetails: UserSecurity) {        val food = getFoodById(id, vendorDetails)        foodRepository.delete(food)    }    @Transactional    fun saveFood(food: Food): Food {        return foodRepository.saveAndFlush(food)    }    @Transactional    fun addOrUpdateFood(foodDto: FoodDto, vendorDetails: UserSecurity): Food {        val vendor = vendorRepository.findById(vendorDetails.id)            .orElseThrow { UserNotFoundException("Vendor not found.") }        // Determine if food is to be created or update an existing one        val food: Food = if (foodDto.id != null) {            foodRepository.findById(foodDto.id!!)                .orElseThrow { RequestedEntityNotFoundException("Food not found.") }                .also {                    if (it.vendor.id != vendorDetails.id) {                        throw PermissionDeniedException("You do not have permission to update food ${it.name}")                    }                }        } else {            Food().apply { this.vendor = vendor }        }        // Input validations        val foodName = requireNotNull(foodDto.foodName) { "Please enter a food name." }        val mainCourse = requireNotNull(foodDto.mainCourse) { "Please enter a main course." }        val description = requireNotNull(foodDto.description) { "Please enter a description." }        val basePrice = requireNotNull(foodDto.basePrice) { "Please enter a base price." }        val preparationTime = requireNotNull(foodDto.preparationTime) { "Please enter a preparation time." }        val deliverable = requireNotNull(foodDto.deliverable) { "Please specify if food is deliverable." }        val dailyDeliveryQuantity = foodDto.dailyDeliveryQuantity        val deliveryTime = foodDto.deliveryTime        val deliveryFee = foodDto.deliveryFee        val availability = Availability.fromString(foodDto.availability)        val readyAsFrom = requireNotNull(foodDto.readyAsFrom) { "Please specify a time when the food will become available." }        val quickDelivery = foodDto.quickDelivery        if (foodDto.id == null) {            // Check if the vendor has already added food with the same name            if (duplicateUtility.isDuplicateFoodFound(foodName, vendorDetails.id)) {                throw DuplicateFoundException("A food with the name: ${foodDto.foodName} already exist. Cannot add duplicate.")            }            food.name = foodName            val lastFood = foodRepository.findTopOrderByFoodNumberDescWithLock().firstOrNull()            val nextNumber = lastFood                ?.foodNumber                ?.takeLast(5)                ?.toInt()                ?.plus(1)                ?: 1            food.foodNumber = "FD-%05d".format(nextNumber)        } else {            if (food.name != foodName) {                if (duplicateUtility.isDuplicateFoodFound(foodName, vendorDetails.id)) {                    throw DuplicateFoundException("A food with the name: ${foodDto.foodName} already exist. Cannot add duplicate.")                }                food.name = foodName            }        }        // Basic info        food.apply {            this.mainCourse = mainCourse            this.description = description            this.basePrice = basePrice            this.preparationTime = preparationTime            this.deliverable = deliverable            this.dailyDeliveryQuantity = dailyDeliveryQuantity            this.deliveryTime = deliveryTime            this.deliveryFee = deliveryFee            this.availability = availability            this.readyAsFrom = readyAsFrom            this.quickDelivery = quickDelivery        }        // Persist food with basic info to make it managed by JPA        val managedFood = saveFood(food)        foodDto.addOns?.let { prepareFoodAddOns(foodDto, managedFood, vendor) } ?: food.foodDiscounts.clear()        managedFood.availableDays = prepareFoodAvailableDays(foodDto, managedFood)        managedFood.foodComplements = prepareFoodComplements(foodDto, managedFood, vendor)        foodDto.discounts?.let { prepareFoodDiscounts(foodDto, managedFood, vendor) } ?: managedFood.foodDiscounts.clear()        managedFood.foodImages = prepareFoodImages(foodDto, managedFood)        managedFood.orderTypes = prepareFoodOrderTypes(foodDto, managedFood)        managedFood.foodSizes = prepareFoodSizes(foodDto, managedFood)        // If updating, retrieve else create a new menu        val menu = prepareMenu(foodDto, managedFood)        menuRepository.save(menu)        saveFood(managedFood)        // Reload the saved food with all relationships        return foodRepository.findByIdWithAllRelations(managedFood.id)            .orElseThrow { RequestedEntityNotFoundException("Food not found.") }    }    private fun prepareMenu(foodDto: FoodDto, food: Food): Menu {        val menu = if (foodDto.id != null) {            menuRepository.findById(food.menu.id)                .getOrElse { throw RequestedEntityNotFoundException("Menu item not found.") }        } else {            Menu().apply {                this.food = food                deliveryItemsLeft = food.dailyDeliveryQuantity // null -> unlimited, 0 -> sold out            }        }        food.orderTypes.forEach { orderType ->            when (orderType) {                /**                 * false -> option not offered                 * true + deliveryItemsLeft = null -> unlimited stock                 * true + deliveryItemsLeft > 0 -> available                 *  true + deliveryItemsLeft = 0 -> sold out                 */                OrderType.DELIVERY -> menu.delivery = true                OrderType.DINE_IN -> menu.dineIn =                    true    // null -> sold out, false -> option not offered, true -> option available                OrderType.PICKUP -> menu.pickup =                    true     // null -> sold out, false -> option not offered, true -> option available                else -> {                    throw IllegalArgumentException("Unknown order type selected.")                }            }        }        return menu    }    private fun prepareFoodAddOns(foodDto: FoodDto, food: Food, vendor: Vendor) {        val existingFoodAddOns = food.foodAddOns.associateBy { it.addOn.id }        val incomingAddOns = foodDto.addOns        val updatedFoodAddOns = incomingAddOns!!.map { dto ->            var addOn = AddOn().apply {                dto.id?.let { this.id = it }                this.vendor = vendor                this.name = requireNotNull(dto.addOnName)                this.price = requireNotNull(dto.price)                this.availability = requireNotNull(Availability.fromString(dto.availability!!))            }            addOn = addOnRepository.saveAndFlush(addOn)            val foodAddOn = dto.id?.let { existingFoodAddOns[it] } ?: FoodAddOn().apply { this.food = food }            foodAddOn.addOn = addOn            foodAddOn        }        food.foodAddOns.removeIf { existingAddOn ->            updatedFoodAddOns.none { it.addOn.id == existingAddOn.addOn.id }        }        updatedFoodAddOns.forEach { updatedFoodAddOn ->            if (food.foodAddOns.none { it.addOn.id == updatedFoodAddOn.addOn.id }) {                food.foodAddOns.add(updatedFoodAddOn)            }        }    }    private fun prepareFoodComplements(foodDto: FoodDto, food: Food, vendor: Vendor): MutableSet<FoodComplement> {        val existingFoodComplements = food.foodComplements.associateBy { it.complement.id }        val incomingComplements = foodDto.complements        if (incomingComplements.isEmpty()) {            throw IllegalArgumentException("A food must have at least one complement.")        }        val updatedFoodComplements = incomingComplements.map { dto ->            var complement = Complement().apply {                dto.id?.let { this.id = it }                this.vendor = vendor                this.name = requireNotNull(dto.complementName)                this.price = requireNotNull(dto.price)                this.availability = Availability.fromString(dto.availability)            }            complement = complementRepository.saveAndFlush(complement)            val foodComplement = dto.id?.let { existingFoodComplements[it] } ?: FoodComplement().apply { this.food = food }            foodComplement.complement = complement            foodComplement        }        food.foodComplements.removeIf { existingFoodComplement ->            updatedFoodComplements.none { it.complement.id == existingFoodComplement.complement.id }        }        updatedFoodComplements.forEach { updatedFoodComplement ->            if (food.foodComplements.none { it.complement.id == updatedFoodComplement.complement.id }) {                food.foodComplements.add(updatedFoodComplement)            }        }        return food.foodComplements    }    private fun prepareFoodDiscounts(foodDto: FoodDto, food: Food, vendor: Vendor) {        val existingFoodDiscounts = food.foodDiscounts.associateBy { it.discount.id }        val incomingDiscounts = foodDto.discounts!!        val updateFoodDiscounts = incomingDiscounts.map { dto ->            var discount = dto.id?.let { id ->                // Reuse the existing managed discount if it exists                discountRepository.findById(id)                    .orElseThrow { RequestedEntityNotFoundException("Discount with id $id not found") }            } ?: Discount().apply {                this.vendor = vendor            }            discount.apply {                discountName = requireNotNull(dto.discountName)                percentage = requireNotNull(dto.percentage)                startDate = requireNotNull(dto.startDate)                endDate = requireNotNull(dto.endDate)            }            discount = discountRepository.save(discount)            val foodDiscount = dto.id?.let { existingFoodDiscounts[it] } ?: FoodDiscount().apply { this.food = food }            foodDiscount.discount = discount            foodDiscount        }        food.foodDiscounts.removeIf { existingFoodDiscount ->            updateFoodDiscounts.none { it.discount.id == existingFoodDiscount.id }        }        updateFoodDiscounts.forEach { updatedFoodDiscount ->            if (food.foodDiscounts.none { it.discount.id == updatedFoodDiscount.discount.id }) {                food.foodDiscounts.add(updatedFoodDiscount)            }        }    }    private fun prepareFoodSizes(foodDto: FoodDto, food: Food): MutableSet<FoodSize> {        val existingFoodSizes = food.foodSizes.associateBy { it.id }        val incomingFoodSizes = foodDto.foodSizes        if (incomingFoodSizes.isEmpty()) {            throw IllegalArgumentException("Please select at least one food size.")        }        val updatedFoodSizes = incomingFoodSizes.map { dto ->            val foodSize = existingFoodSizes[dto.id] ?: FoodSize().apply { this.food = food }            foodSize.apply {                size = Size.fromString(requireNotNull(dto.size))                name = (dto.sizeName) ?: this.size!!.name                priceIncrease = dto.priceIncrease                availability = requireNotNull(Availability.fromString(dto.availability!!))            }        }        food.foodSizes.removeIf { existingSize ->            updatedFoodSizes.none { it.id == existingSize.id }        }        updatedFoodSizes.forEach { updatedSize ->            if (food.foodSizes.none { it.id == updatedSize.id }) {                food.foodSizes.add(updatedSize)            }        }        return food.foodSizes    }    private fun prepareFoodAvailableDays(foodDto: FoodDto, food: Food): MutableSet<Day> {        val existingAvailableDays = food.availableDays        val incomingAvailableDays = if (foodDto.availableDays.isEmpty()) {            throw IllegalArgumentException("At least one day must be selected.")        } else {            foodDto.availableDays.map { Day.fromString(it) }.toSet()        }        existingAvailableDays.removeIf { it !in incomingAvailableDays }        incomingAvailableDays.forEach { availableDay ->            if (availableDay !in existingAvailableDays) {                existingAvailableDays.add(availableDay)            }        }        return existingAvailableDays    }    private fun prepareFoodOrderTypes(foodDto: FoodDto, food: Food): MutableSet<OrderType> {        val existingOrderTypes = food.orderTypes        val incomingOrderTypes = if (foodDto.orderTypes.isEmpty()) {            throw IllegalArgumentException("At least one order type must be selected.")        } else {            foodDto.orderTypes.map { OrderType.fromString(it) }.toSet()        }        existingOrderTypes.removeIf { it !in incomingOrderTypes }        // Add any new types that don't already exist        incomingOrderTypes.forEach { orderType ->            if (orderType !in existingOrderTypes) {                existingOrderTypes.add(orderType)            }        }        return existingOrderTypes    }    private fun prepareFoodImages(foodDto: FoodDto, food: Food): MutableSet<FoodImage> {        val existingFoodImages = food.foodImages.associateBy { it.id }        val incomingImages = foodDto.foodImages        if (incomingImages.isEmpty() || incomingImages.size < 2) {            throw IllegalArgumentException("Please add at least 2 images of the food")        }        val updatedFoodImages = incomingImages.map { dto ->            val image = existingFoodImages[dto.id] ?: FoodImage().apply { this.food = food }            image.imageUrl = dto.imageUrl            image        }        food.foodImages.removeIf { existingImage ->            updatedFoodImages.none { it.id == existingImage.id }        }        updatedFoodImages.forEach { updatedImage ->            if (food.foodImages.none { it.id == updatedImage.id }) {                food.foodImages.add(updatedImage)            }        }        return food.foodImages    }}